(6, 6, 12, 10, '🔥 BÁN CĂN 2PN FULL NỘI THẤT CAO CẤP – VINHOMES WEST POINT🔥', 'ban-can-2pn-full-noi-that-cao-cap-vinhomes-west-point-6', 'BDS-0006', 'can_ho', 'ban', 'W2.3705a', 'W1', '37', 'Đông Nam', 'Tây Bắc', 65.10, '2n2vs', 'cao_cap', '<p><strong>B&Aacute;N CĂN 2n2vs FULL NỘI THẤT CAO CẤP &ndash; VINHOMES WEST POINT</strong></p>\r\n\r\n<blockquote>\r\n<p><samp>Diện t&iacute;ch 65.1m&sup2;, full nội thất cao cấp.</samp></p>\r\n\r\n<p><samp>Sẵn kh&aacute;ch thu&ecirc; 22 triệu/th&aacute;ng, mua l&agrave; c&oacute; d&ograve;ng tiền ngay.</samp></p>\r\n\r\n<p><samp>Dự &aacute;n vị tr&iacute; đẹp, tiện &iacute;ch đồng bộ, dễ ở v&agrave; dễ cho thu&ecirc;.</samp></p>\r\n</blockquote>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Gi&aacute; 9,5 tỷ c&oacute; thương lượng, sổ đỏ r&otilde; r&agrave;ng</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<p>&ldquo;Căn hộ ph&ugrave; hợp cả kh&aacute;ch mua ở cần một kh&ocirc;ng gian chỉn chu, lẫn kh&aacute;ch đầu tư muốn sở hữu t&agrave;i sản c&oacute; sẵn kh&aacute;ch thu&ecirc;, ph&aacute;p l&yacute; r&otilde; r&agrave;ng v&agrave; nằm trong quần thể Vinhomes West Point c&oacute; tiện &iacute;ch ho&agrave;n chỉnh, vị tr&iacute; thuận tiện bậc nhất khu T&acirc;y.&rdquo;</p>\r\n\r\n<p>Điểm cộng lớn của căn l&agrave; nằm trong quần thể Vinhomes West Point với hệ tiện &iacute;ch nội khu đồng bộ gồm trung t&acirc;m thương mại, shophouse, si&ecirc;u thị, bể bơi 4 m&ugrave;a, gym, spa, khu vui chơi trẻ em, khu sinh hoạt cộng đồng v&agrave; an ninh 24/24.</p>\r\n\r\n<p><br />\r\nDự &aacute;n tọa lạc tại vị tr&iacute; đẹp ngay Đỗ Đức Dục - Phạm H&ugrave;ng, kết nối nhanh tới c&aacute;c tuyến giao th&ocirc;ng lớn v&agrave; h&agrave;ng loạt c&ocirc;ng tr&igrave;nh trọng điểm như Trung t&acirc;m Hội nghị Quốc gia, JW Marriott, Bảo t&agrave;ng H&agrave; Nội v&agrave; Landmark 72.</p>\r\n\r\n<p><br />\r\nĐ&acirc;y l&agrave; lựa chọn ph&ugrave; hợp cho kh&aacute;ch mua ở cần m&ocirc;i trường sống hiện đại, cũng như kh&aacute;ch đầu tư muốn sở hữu căn hộ c&oacute; vị tr&iacute; tốt, tiện &iacute;ch đầy đủ v&agrave; khả năng khai th&aacute;c cho thu&ecirc; ổn định.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>', NULL, 'bat-dong-san/Ahcrgo4QUJ4TfDP4kPZujnTaRVhqPQ9uoaCORt7T.jpg', '[\"bat-dong-san\\/album\\/u1YqEgxNrtd0pMgsZozmAWYf6AQefgg63nrsQxoI.jpg\",\"bat-dong-san\\/album\\/IeYljUc7JzV51oOwXu70CTxMRRAPHwwqeVXiPR6L.jpg\",\"bat-dong-san\\/album\\/Y8z3iMfd7VAPxCicEM5ipBdmjDesU9z98yD2wodr.jpg\",\"bat-dong-san\\/album\\/5HZoQK9ZEPdKIi8Y3QEV5VIrA5rVQxaUTX33vygh.jpg\"]', NULL, 9500000000.00, 95000000.00, NULL, 'so_hong', NULL, NULL, NULL, 0, 1, 1, 'con_hang', 464, 6, NULL, NULL, NULL, '2026-03-09 17:00:00', '2026-04-04 11:39:22', '2026-04-11 12:32:49', NULL),
