(8, 8, 10, 3, '🔥 SIÊU PHẨM 2PN VIEW THOÁNG – GIÁ TỐT NHẤT D\'CAPITALE 🔥', 'sieu-pham-2pn-view-thoang-gia-tot-nhat-dcapitale-8', 'BDS-0008', 'can_ho', 'ban', 'C2.2602', 'C1', 'Tầng 26', 'Đông Nam', 'Tây Bắc', 68.20, '2n2vs', 'full', '<p>📞 <strong>Li&ecirc;n hệ xem nh&agrave; (hẹn trước): 0962501832</strong></p>\r\n\r\n<p><strong>Cam kết th&ocirc;ng tin chuẩn &ndash; hỗ trợ ph&aacute;p l&yacute; A-Z</strong></p>\r\n\r\n<p><strong>Tư vấn nhiệt t&igrave;nh, l&agrave;m việc chuy&ecirc;n nghiệp</strong></p>\r\n\r\n<p>🏙️ Căn hộ thuộc khu đ&ocirc; thị cao cấp Vinhomes D&#39;Capitale &ndash; trung t&acirc;m quận Cầu Giấy, vị tr&iacute; v&agrave;ng ngay ng&atilde; tư Trần Duy Hưng &ndash; Khuất Duy Tiến.</p>\r\n\r\n<blockquote>\r\n<p><samp><code>Diện t&iacute;ch: <strong>68.2m&sup2;</strong></code></samp></p>\r\n\r\n<p><samp><code>Thiết kế: <strong>2 ph&ograve;ng ngủ &ndash; 2 vệ sinh</strong></code></samp></p>\r\n\r\n<p><samp><code>Hướng cửa: <strong>Đ&ocirc;ng Nam</strong> &ndash; đ&oacute;n gi&oacute; m&aacute;t</code></samp></p>\r\n\r\n<p><samp><code>Ban c&ocirc;ng: <strong>T&acirc;y Bắc</strong> &ndash; view tho&aacute;ng, &aacute;nh s&aacute;ng tốt</code></samp></p>\r\n\r\n<p><samp><code>Nội thất: <strong>Full nội thất cao cấp &ndash; v&agrave;o ở ngay</strong></code></samp></p>\r\n\r\n<p><samp><code>T&igrave;nh trạng: <strong>Đang cho thu&ecirc; đến th&aacute;ng 5 &ndash; c&oacute; d&ograve;ng tiền sẵn</strong></code></samp></p>\r\n\r\n<p><samp><code>Ph&aacute;p l&yacute;: <strong>Sổ đỏ&nbsp;</strong></code></samp></p>\r\n</blockquote>\r\n\r\n<p>👉 Gi&aacute; cực cạnh tranh trong ph&acirc;n kh&uacute;c 2PN</p>\r\n\r\n<p><strong>🌟 Điểm mạnh nổi bật:</strong></p>\r\n\r\n<p>✔️ Căn hộ tầng đẹp, layout tối ưu, kh&ocirc;ng gian sống tho&aacute;ng<br />\r\n✔️ Ph&ugrave; hợp: <strong>ở thực &ndash; đầu tư cho thu&ecirc; &ndash; giữ t&agrave;i sản</strong><br />\r\n✔️ Kh&aacute;ch mua c&oacute; thể tiếp tục hợp đồng thu&ecirc;, d&ograve;ng tiền ổn định</p>\r\n\r\n<p>📍 <strong>Kết nối giao th&ocirc;ng thuận tiện:</strong></p>\r\n\r\n<ul>\r\n	<li>Nhanh ch&oacute;ng tới Keangnam Landmark 72</li>\r\n	<li>Gần Trung t&acirc;m Hội nghị Quốc gia</li>\r\n	<li>Dễ d&agrave;ng di chuyển sang Thanh Xu&acirc;n, Mỹ Đ&igrave;nh, Nam Từ Li&ecirc;m</li>\r\n</ul>\r\n\r\n<p><strong>🏢 Tiện &iacute;ch đẳng cấp tại D&#39;Capitale:</strong></p>\r\n\r\n<ul>\r\n	<li>🌳 C&ocirc;ng vi&ecirc;n nội khu, đường dạo bộ, kh&ocirc;ng gian xanh</li>\r\n	<li>🏊&zwj;♂️ Hệ thống <strong>bể bơi 4 m&ugrave;a &amp; ngo&agrave;i trời</strong></li>\r\n	<li>🛍️ Trung t&acirc;m thương mại Vincom Center Tran Duy Hung ngay khối đế</li>\r\n	<li>🏋️&zwj;♂️ Ph&ograve;ng gym, yoga hiện đại</li>\r\n	<li>🎬 Rạp chiếu phim, khu vui chơi trẻ em</li>\r\n	<li>🏫 Gần trường học quốc tế, trường li&ecirc;n cấp Vinschool</li>\r\n	<li>🏥 Gần bệnh viện quốc tế, tiện chăm s&oacute;c sức khỏe</li>\r\n	<li>🔐 An ninh 24/7, lễ t&acirc;n chuy&ecirc;n nghiệp</li>\r\n</ul>', NULL, 'bat-dong-san/ZPUtGKKoL8ysoBZxSt6j5U1rpbdjs9rJtD0NO7lt.jpg', '[\"bat-dong-san\\/album\\/0dZ66ZsdmTunGbBrKkYFmeMxUTtZIujqmbd4e5B8.jpg\",\"bat-dong-san\\/album\\/JQPwvn0XGlaHtzE6XhGfH9UBFXy0Y90muIN0MbUV.jpg\",\"bat-dong-san\\/album\\/bixiJq085R19j7HwO5iv3gMBGq0ma9YsTAZUEtX0.jpg\",\"bat-dong-san\\/album\\/rMq4Y3ennlArdY1gWOfbw5B1zbu7hPzFqQW1ned0.jpg\",\"bat-dong-san\\/album\\/G6z0fr4tmOWwWhJIa23MdJ04KYYOOdrTYtwcKx2i.jpg\",\"bat-dong-san\\/album\\/UGAqOZbZX2j58EExtEMOSCmzUg3Hk54YD5nIoqOp.jpg\"]', NULL, 8800000000.00, 8800000000.00, NULL, 'so_hong', NULL, NULL, NULL, 1, 1, 1, 'con_hang', 160, 1, NULL, NULL, NULL, '2026-04-10 17:00:00', '2026-04-04 11:39:22', '2026-04-19 10:17:10', NULL),
(9, 9, 12, 3, '✨ CHUYỂN NHƯỢNG CĂN 2PN+ ĐẸP TẠI SAPPHIRE TOÀ S102', 'chuyen-nhuong-can-2pn-dep-tai-sapphire-toa-s102-9', 'BDS-0009', 'can_ho', 'ban', 'S102.2405A', 'S102', '24', 'Tây Nam', 'Đông Bắc', 63.30, '2n2vs+', 'full', '<p>🏙️&nbsp;<strong>B&Aacute;N CĂN 2PN+ &ndash; T&Ograve;A S102 SAPPHIRE</strong></p>\r\n\r\n<blockquote>\r\n<p><samp>📐 Diện t&iacute;ch 63,3m&sup2;, thiết kế 2PN + 2VS+, c&ocirc;ng năng tối ưu cho gia đ&igrave;nh trẻ hoặc kh&aacute;ch đầu tư</samp></p>\r\n\r\n<p><samp>🛋️ Căn hộ full nội thất, chỉ việc nhận nh&agrave; v&agrave; sử dụng</samp></p>\r\n\r\n<p><samp>📕 Sổ đỏ đầy đủ, giao dịch an t&acirc;m</samp></p>\r\n\r\n<p><samp>💰 Gi&aacute; b&aacute;n 5.750 tỷ thu về</samp></p>\r\n\r\n<p><samp>💵 Đang c&oacute; sẵn kh&aacute;ch thu&ecirc; 12 triệu/th&aacute;ng, ph&ugrave; hợp kh&aacute;ch mua giữ t&agrave;i sản v&agrave; c&oacute; d&ograve;ng tiền ổn định</samp></p>\r\n\r\n<p><samp>🌟 Đ&acirc;y l&agrave; lựa chọn ph&ugrave; hợp cho cả kh&aacute;ch mua ở thực lẫn kh&aacute;ch đầu tư muốn sở hữu căn hộ đẹp, ph&aacute;p l&yacute; r&otilde;, khai th&aacute;c ngay</samp></p>\r\n\r\n<p><samp>📞 Li&ecirc;n hệ: 0962501832 để xem nh&agrave; v&agrave; chốt căn gi&aacute; tốt</samp></p>\r\n</blockquote>\r\n\r\n<p><strong>Tiện &iacute;ch nội khu</strong></p>\r\n\r\n<p>🏊 Hệ tiện &iacute;ch nội khu nổi bật với bộ 3 c&ocirc;ng vi&ecirc;n li&ecirc;n ho&agrave;n gồm Central Park, Sportia Park v&agrave; Zen Park, tạo kh&ocirc;ng gian sống xanh, rộng v&agrave; nhiều khu trải nghiệm cho cư d&acirc;n.</p>\r\n\r\n<p>🌳 Central Park rộng 10,2ha, c&oacute; hồ trung t&acirc;m 4,8ha, b&atilde;i c&aacute;t trắng v&agrave; nhiều khu vận động, thư gi&atilde;n ngo&agrave;i trời.</p>\r\n\r\n<p>💪 Sportia Park l&agrave; c&ocirc;ng vi&ecirc;n thể thao quy m&ocirc; lớn với 163 s&acirc;n tập thể thao v&agrave; hơn 1.000 m&aacute;y tập gym ngo&agrave;i trời, ph&ugrave; hợp cư d&acirc;n y&ecirc;u th&iacute;ch vận động hằng ng&agrave;y.</p>\r\n\r\n<p>🏀 Nội khu c&ograve;n c&oacute; s&acirc;n tennis, b&oacute;ng rổ, cầu l&ocirc;ng, b&oacute;ng chuyền, khu aerobic, khu xe đạp địa h&igrave;nh v&agrave; s&acirc;n chơi đa năng cho nhiều lứa tuổi.</p>\r\n\r\n<p>🏊&zwj;♀️ Dự &aacute;n c&oacute; hệ thống bể bơi ngo&agrave;i trời v&agrave; bể bơi 4 m&ugrave;a phong c&aacute;ch resort, phục vụ nhu cầu thư gi&atilde;n v&agrave; r&egrave;n luyện quanh năm.</p>\r\n\r\n<p>👧 C&oacute; khu vui chơi trẻ em, khu BBQ, đường dạo bộ, ch&ograve;i nghỉ, thư viện v&agrave; ph&ograve;ng sinh hoạt cộng đồng ngay trong khu đ&ocirc; thị.</p>\r\n\r\n<p>🏫 Trong hệ sinh th&aacute;i dự &aacute;n c&ograve;n c&oacute; Vinschool, Vinmec v&agrave; Vincom Mega Mall, gi&uacute;p cư d&acirc;n thuận tiện hơn về học tập, chăm s&oacute;c sức khỏe v&agrave; mua sắm.</p>\r\n\r\n<p><strong>Tiện &iacute;ch ngoại khu</strong></p>\r\n\r\n<p>🚗 Vinhomes Smart City nằm ở khu T&acirc;y H&agrave; Nội n&ecirc;n hưởng lợi lớn về kết nối tới c&aacute;c khu đ&ocirc; thị, trung t&acirc;m thương mại v&agrave; hệ dịch vụ đang ph&aacute;t triển mạnh trong khu vực.</p>\r\n\r\n<p>🛍️ Ngoại khu gần AEON Mall H&agrave; Đ&ocirc;ng v&agrave; c&aacute;c cụm mua sắm, si&ecirc;u thị tiện &iacute;ch, thuận tiện cho nhu cầu mua sắm, giải tr&iacute; v&agrave; ăn uống.</p>\r\n\r\n<p>🏙️ Lợi thế của khu vực n&agrave;y l&agrave; cư d&acirc;n vừa được sử dụng hệ sinh th&aacute;i lớn b&ecirc;n trong đại đ&ocirc; thị, vừa dễ tiếp cận th&ecirc;m nhiều tiện &iacute;ch đ&ocirc; thị ph&iacute;a T&acirc;y H&agrave; Nội ở b&ecirc;n ngo&agrave;i.</p>\r\n\r\n<p>📈 Với kh&aacute;ch mua ở hoặc đầu tư cho thu&ecirc;, vị tr&iacute; tại đại đ&ocirc; thị Smart City gi&uacute;p căn hộ dễ tiếp cận nh&oacute;m kh&aacute;ch trẻ, gia đ&igrave;nh trẻ v&agrave; kh&aacute;ch thu&ecirc; ưu ti&ecirc;n m&ocirc;i trường sống đồng bộ</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>', NULL, 'bat-dong-san/9vxg6PqtwSCKrquMFxDVQ5Pv9d3lPaDMoL1xVbtQ.jpg', '[\"bat-dong-san\\/album\\/TzHcaD4F0sB79o6RwGIBgeF83vEGP0pGJ16TgIVh.jpg\",\"bat-dong-san\\/album\\/8KN0bMErFWw3PWVKJbDcwMqOj5ivOj01byXbf0qu.jpg\",\"bat-dong-san\\/album\\/QjsNu8OK67U5dPwjhFrPR9UL1HKjCR6tSQmKxCWV.jpg\",\"bat-dong-san\\/album\\/ZqWm4ML6mZJrpOJFx7mH4maFhABhW6vCYzqGxsm3.jpg\",\"bat-dong-san\\/album\\/H55Wy1dh4bC4AkXo4leMgQqHYPv7OpGYhPtq5KsH.jpg\",\"bat-dong-san\\/album\\/gsKC8CBp4ek2FGaSs9kw8O0TIuP2GR7lk1OP3HzU.jpg\"]', NULL, 6000000000.00, 6000000.00, NULL, 'so_hong', NULL, NULL, NULL, 1, 1, 1, 'con_hang', 469, 9, 'Vinhomes Smart City Toà S102 - Thành Công Land', NULL, NULL, '2026-02-21 17:00:00', '2026-04-04 11:39:22', '2026-04-15 01:42:13', NULL),
