(51, 4, 7, 10, '✨ CHO THUÊ CĂN 2N1VS TRONG DUALKEY FULL NỘI THẤT – THE MATRIX ONE', 'cho-thue-can-2n1vs-trong-dualkey-full-noi-that-the-matrix-one-51', 'BDS-H4NOED', 'can_ho', 'thue', NULL, 'B', '14', 'Đông Bắc', 'Tây Nam', 111.70, '2n1vs', 'full', '<p>✨&nbsp;<strong>CHO THU&Ecirc; CĂN HỘ 2N1VS TRONG DUALKEY FULL NỘI THẤT TẠI THE MATRIX ONE&nbsp;</strong></p>\r\n\r\n<blockquote>\r\n<p><samp>📐 Diện t&iacute;ch:&nbsp;<strong>111,67m&sup2;</strong></samp></p>\r\n\r\n<p><samp>🧩 Loại căn:&nbsp;<strong>Dualkey (CHO THU&Ecirc; 1 B&Ecirc;N DUALKEY)</strong></samp></p>\r\n\r\n<p><samp>🌤️ Hướng:&nbsp;<strong>ĐB/TN</strong></samp></p>\r\n\r\n<p><samp>💰&nbsp;<strong>2N1VS: 23 triệu/th&aacute;ng</strong></samp></p>\r\n\r\n<p><samp>📄 Tiến độ thanh to&aacute;n:&nbsp;<strong>6 cọc 1</strong></samp></p>\r\n\r\n<p><samp>🛋️ Nội thất:&nbsp;<strong>Full nội thất</strong></samp></p>\r\n</blockquote>\r\n\r\n<p><strong>Tiện &iacute;ch nội khu</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>🏊 Khu căn hộ c&oacute; hệ tiện &iacute;ch đồng bộ, ph&ugrave; hợp nhu cầu sống hiện đại v&agrave; nghỉ ngơi ngay trong nội khu.</p>\r\n	</li>\r\n	<li>\r\n	<p>💪 Tiện &iacute;ch thường được kh&aacute;ch thu&ecirc; quan t&acirc;m gồm bể bơi, ph&ograve;ng gym, khu&ocirc;n vi&ecirc;n dạo bộ, khu vui chơi trẻ em v&agrave; khu sinh hoạt chung.</p>\r\n	</li>\r\n	<li>\r\n	<p>🛡️ An ninh đảm bảo, sảnh t&ograve;a nh&agrave; chỉn chu, lễ t&acirc;n v&agrave; hệ thống quản l&yacute; vận h&agrave;nh chuy&ecirc;n nghiệp gi&uacute;p cư d&acirc;n y&ecirc;n t&acirc;m khi sinh sống.</p>\r\n	</li>\r\n	<li>\r\n	<p>🚗 C&oacute; hầm để xe, thang m&aacute;y v&agrave; hạ tầng nội khu thuận tiện cho sinh hoạt hằng ng&agrave;y.</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Tiện &iacute;ch ngoại khu</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>🚘 Dự &aacute;n nằm ở khu vực ph&iacute;a T&acirc;y H&agrave; Nội, thuận tiện di chuyển tới c&aacute;c trục đường lớn v&agrave; khu văn ph&ograve;ng.</p>\r\n	</li>\r\n	<li>\r\n	<p>🏙️ Ph&ugrave; hợp với kh&aacute;ch l&agrave;m việc ở khu Mỹ Đ&igrave;nh, Nam Từ Li&ecirc;m, Cầu Giấy hoặc thường xuy&ecirc;n cần di chuyển nhanh v&agrave;o trung t&acirc;m.</p>\r\n	</li>\r\n	<li>\r\n	<p>🛍️ Xung quanh c&oacute; nhiều tiện &iacute;ch đ&ocirc; thị như trung t&acirc;m thương mại, nh&agrave; h&agrave;ng, qu&aacute;n c&agrave; ph&ecirc;, trường học, văn ph&ograve;ng v&agrave; dịch vụ sinh hoạt hằng ng&agrave;y.</p>\r\n	</li>\r\n	<li>\r\n	<p>🏢 Đ&acirc;y l&agrave; lựa chọn ph&ugrave; hợp cho kh&aacute;ch thu&ecirc; muốn ở tại khu vực hiện đại, hạ tầng tốt v&agrave; kết nối thuận tiện.</p>\r\n	</li>\r\n</ul>', NULL, NULL, '[\"bat-dong-san\\/album\\/T1N2TLB9dCuUGjBJJIjl1dqM8ldL2yI0fTS8hdb6.jpg\",\"bat-dong-san\\/album\\/wIMR1yQbC2Wx7Va5PtYdPLbGrmh30aMtVTuek7c0.jpg\",\"bat-dong-san\\/album\\/Lo3meIpbYEoU684vZXaD2VyOxtM5NcfnQdWvMLlf.jpg\",\"bat-dong-san\\/album\\/pPLG4bxMt6Bx1K9vzrxpTloK2WTL8u71r1dkRmh0.jpg\",\"bat-dong-san\\/album\\/aQ7bPsOnaQjXHeIs11nT45SIaEkUPkXLKvoc3Dsp.jpg\",\"bat-dong-san\\/album\\/5ukatpDrhKN254dpbAdwuI5QpKO9Jle4O207nVi1.jpg\"]', '[\"bat-dong-san\\/video\\/fMTp7tcSF5AAd3OQQ1spIXNN7eU0Kaww7NdpqMYP.mp4\"]', NULL, NULL, NULL, NULL, 23000000.00, 'ngay_lap_tuc', 'thang_6', 0, 1, 1, 'con_hang', 29, 0, NULL, NULL, NULL, '2026-04-16 17:00:00', '2026-04-17 12:15:13', '2026-04-17 12:56:06', '2026-04-17 12:56:06');
