(1, 1, 1, NULL, 'khach_hang', 'van_ban', 'Xin chào, tôi muốn tìm căn hộ 2 phòng ngủ tại Vinhomes Smart City.', NULL, 1, '2026-04-04 11:14:23', '2026-04-04 10:04:23', '2026-04-04 11:39:23'),
(2, 1, NULL, 4, 'nhan_vien', 'van_ban', 'Chào bạn! Hiện tại chúng tôi có một số căn hộ 2PN tại Vinhomes Smart City. Bạn có thể cho biết mức ngân sách dự kiến không ạ?', NULL, 1, '2026-04-04 11:16:23', '2026-04-04 11:13:23', '2026-04-04 11:39:23'),
(12, 6, NULL, NULL, 'he_thong', 'van_ban', 'Xin chào! Tôi là trợ lý AI của Thành Công Land. Tôi có thể hỗ trợ bạn ngay bây giờ.', NULL, 1, NULL, '2026-04-05 08:42:41', '2026-04-05 08:42:41'),
(14, 6, 13, NULL, 'khach_hang', 'van_ban', 'xin hàp', NULL, 1, '2026-04-08 11:58:26', '2026-04-08 11:57:29', '2026-04-08 11:58:26'),
(15, 6, NULL, NULL, 'bot', 'van_ban', 'Chào anh Hiếu,\n\nThành Công Land xin chào anh ạ!\n\nAnh đang quan tâm đến căn hộ 3 phòng ngủ tại Vinhomes Smart City với giá thuê 13 triệu/tháng và diện tích 89m² phải không ạ? Đây là một lựa chọn rất tốt với đầy đủ tiện nghi và an ninh đảm bảo.\n\nAnh có câu hỏi nào về căn hộ này hoặc muốn tìm hiểu thêm thông tin chi tiết không ạ? Tôi sẵn lòng hỗ trợ anh.', NULL, 1, '2026-04-08 11:57:36', '2026-04-08 11:57:35', '2026-04-08 11:57:36'),
(16, 6, NULL, NULL, 'he_thong', 'van_ban', 'Yeu cau cua ban da duoc chuyen cho nhan vien kinh doanh. Vui long doi trong giay lat.', NULL, 1, NULL, '2026-04-08 11:57:45', '2026-04-08 11:57:45'),
(17, 6, NULL, NULL, 'he_thong', 'van_ban', 'Yeu cau cua ban da duoc chuyen cho nhan vien kinh doanh. Vui long doi trong giay lat.', NULL, 1, NULL, '2026-04-08 11:57:45', '2026-04-08 11:57:45'),
(28, 1, NULL, 4, 'nhan_vien', 'van_ban', 'Anh/chị cho em xin số điện thoại để liên hệ nhanh hơn.', NULL, 0, NULL, '2026-04-11 12:37:40', '2026-04-11 12:37:40'),
