INSERT INTO `tin_tuyen_dung` (`id`, `tieu_de`, `slug`, `phong_ban`, `hinh_thuc`, `dia_diem`, `so_luong`, `muc_luong`, `tag`, `tag_color`, `mo_ta_ngan`, `mo_ta_cong_viec`, `yeu_cau`, `quyen_loi`, `han_nop`, `hien_thi`, `noi_bat`, `thu_tu`, `nhan_vien_id`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Chuyên viên kinh', 'chuyen-vien-kinh-Pj9DF', NULL, 'toan_thoi_gian', NULL, 10, '5 - 7 Triệu', NULL, 'danger', NULL, NULL, NULL, NULL, '2027-10-26', 1, 0, 0, 7, '2026-04-26 09:20:52', '2026-04-26 09:20:59', '2026-04-26 09:20:59'),
(2, 'Chuyên viên kinh', 'chuyen-vien-kinh-trwCb', NULL, 'toan_thoi_gian', NULL, 10, '5 - 7 Triệu', NULL, 'danger', NULL, NULL, NULL, NULL, '2027-10-26', 1, 0, 0, 7, '2026-04-26 09:20:53', '2026-04-26 09:37:27', '2026-04-26 09:37:27'),
(3, 'Chuyên Viên Kinh Doanh Bất Động Sản Cao Cấp', 'chuyen-vien-kinh-doanh-bat-dong-san-cao-cap-vtIWp', 'Phòng Kinh doanh', 'full_time', 'Vinhomes Smart City, Hà Nội', 20, '15 - 50 Triệu', 'Hot - Thu nhập khủng', 'danger', '- Tìm kiếm và khai thác khách hàng tiềm năng có nhu cầu mua/thuê BĐS.\n- Tư vấn các dự án BĐS trọng điểm của công ty (Vinhomes, Masterise...).\n- Chăm s...', '- Tìm kiếm và khai thác khách hàng tiềm năng có nhu cầu mua/thuê BĐS.\n- Tư vấn các dự án BĐS trọng điểm của công ty (Vinhomes, Masterise...).\n- Chăm sóc khách hàng, hỗ trợ thủ tục ký kết hợp đồng.\n- Thực hiện các chiến dịch marketing cá nhân để tìm kiếm data.', '- Đam mê kinh doanh, chịu khó, có tinh thần cầu tiến.\n- Có khả năng giao tiếp tốt, không nói ngọng/nói lắp.\n- Ưu tiên ứng viên có kinh nghiệm trong ngành BĐS, bảo hiểm, tài chính.\n- Có laptop và phương tiện đi lại cá nhân.', '- Lương cứng lũy tiến + Hoa hồng cao nhất thị trường (30% - 60%).\n- Thưởng nóng theo từng giao dịch và thưởng quý/năm hấp dẫn.\n- Được đào tạo bài bản từ A-Z về kỹ năng sale và marketing.\n- Môi trường làm việc năng động, trẻ trung, chuyên nghiệp.', NULL, 1, 1, 0, 1, '2026-04-26 09:36:59', '2026-04-26 09:36:59', NULL),
(4, 'Chuyên Viên Digital Marketing (Ads & Nội dung)', 'chuyen-vien-digital-marketing-ads-noi-dung-i3ndF', 'Phòng Marketing', 'full_time', 'Tòa SA5, Vinhome Smart City', 2, '10 - 18 Triệu', 'Tuyển gấp', 'warning', '- Lên kế hoạch và thực thi các chiến dịch quảng cáo (Facebook, Google, TikTok).\n- Quản trị fanpage, website và các kênh social của công ty.\n- Sáng tạo...', '- Lên kế hoạch và thực thi các chiến dịch quảng cáo (Facebook, Google, TikTok).\n- Quản trị fanpage, website và các kênh social của công ty.\n- Sáng tạo nội dung, viết bài SEO, thiết kế hình ảnh/video cơ bản cho dự án.\n- Theo dõi, đo lường và tối ưu hóa hiệu quả các chiến dịch.', '- Tối thiểu 1 năm kinh nghiệm chạy Ads BĐS hoặc ngành liên quan.\n- Sử dụng tốt các công cụ tracking và phân tích dữ liệu.\n- Có tư duy sáng tạo, khả năng viết lách tốt.\n- Biết sử dụng Canva/Photoshop/Capcut là một lợi thế.', '- Mức lương cạnh tranh theo năng lực.\n- Được làm việc với ngân sách quảng cáo lớn cho các dự án HOT.\n- Đóng BHXH, BHYT đầy đủ theo quy định nhà nước.\n- Du lịch, team building hàng quý cùng công ty.', NULL, 1, 0, 0, 1, '2026-04-26 09:36:59', '2026-04-26 09:36:59', NULL),
(5, 'Trưởng Nhóm Kinh Doanh (Team Leader)', 'truong-nhom-kinh-doanh-team-leader-73S7w', 'Khối Kinh doanh', 'full_time', 'Nam Từ Liêm, Hà Nội', 3, '20 - 70 Triệu', 'Cấp quản lý', 'navy', '- Xây dựng, quản lý và đào tạo đội ngũ nhân viên kinh doanh (5-10 người).\n- Lên kế hoạch kinh doanh và chịu trách nhiệm về doanh số của nhóm.\n- Hỗ trợ...', '- Xây dựng, quản lý và đào tạo đội ngũ nhân viên kinh doanh (5-10 người).\n- Lên kế hoạch kinh doanh và chịu trách nhiệm về doanh số của nhóm.\n- Hỗ trợ nhân viên trong việc chốt deal và xử lý các tình huống khó.\n- Báo cáo kết quả kinh doanh định kỳ cho Ban Giám đốc.', '- Ít nhất 2 năm kinh nghiệm sale BĐS và 1 năm ở vị trí quản lý tương đương.\n- Có khả năng lãnh đạo, truyền cảm hứng và đào tạo đội ngũ.\n- Kỹ năng đàm phán và thuyết phục khách hàng xuất sắc.\n- Am hiểu sâu sắc thị trường BĐS khu vực phía Tây Hà Nội.', '- Cơ chế lương quản lý + Hoa hồng nhóm cực kỳ hấp dẫn.\n- Hỗ trợ chi phí marketing và data khách hàng chất lượng.\n- Lộ trình thăng tiến lên Giám đốc sàn trong vòng 6-12 tháng.\n- Cấp phòng làm việc riêng và các trang thiết bị hiện đại.', NULL, 1, 1, 0, 1, '2026-04-26 09:36:59', '2026-04-26 09:36:59', NULL),
(6, 'Nhân Viên Hành Chính Nhân Sự Tổng Hợp', 'nhan-vien-hanh-chinh-nhan-su-tong-hop-9khPe', 'Phòng Hành chính', 'full_time', 'Vinhomes Smart City', 1, '8 - 12 Triệu', 'Môi trường tốt', 'success', '- Thực hiện công tác tuyển dụng nhân sự theo nhu cầu của các phòng ban.\n- Quản lý hồ sơ nhân sự, theo dõi chấm công và tính lương.\n- Phụ trách các côn...', '- Thực hiện công tác tuyển dụng nhân sự theo nhu cầu của các phòng ban.\n- Quản lý hồ sơ nhân sự, theo dõi chấm công và tính lương.\n- Phụ trách các công việc hành chính văn phòng, mua sắm văn phòng phẩm.\n- Phối hợp tổ chức các sự kiện nội bộ, team building của công ty.', '- Tốt nghiệp đại học chuyên ngành Nhân sự, Hành chính, Luật hoặc liên quan.\n- Cẩn thận, trung thực, có kỹ năng sắp xếp công việc khoa học.\n- Thành thạo tin học văn phòng (Word, Excel, PowerPoint).\n- Ưu tiên ứng viên có kinh nghiệm tuyển dụng trong ngành BĐS.', '- Môi trường làm việc thân thiện, hòa đồng.\n- Nghỉ lễ, Tết theo quy định, thưởng lương tháng 13.\n- Được tham gia các khóa đào tạo nâng cao nghiệp vụ nhân sự.\n- Thưởng thâm niên và các chế độ phúc lợi khác.', NULL, 1, 0, 0, 1, '2026-04-26 09:36:59', '2026-04-26 09:36:59', NULL);
